"use client";

import Link from "next/link";
import { useCallback, useEffect, useMemo, useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { ApplicantStatusBadge } from "@/components/applicants/applicant-status-badge";
import { apiFetch } from "@/lib/api";
import type { Applicant, ApplicantStatus } from "@/lib/types";

const statuses: Array<ApplicantStatus | "All"> = ["All", "Applied", "Screening", "Interview", "Offered", "Hired", "Rejected"];

export function ApplicantTable() {
  const [applicants, setApplicants] = useState<Applicant[]>([]);
  const [search, setSearch] = useState("");
  const [status, setStatus] = useState<ApplicantStatus | "All">("All");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const query = useMemo(() => {
    const params = new URLSearchParams({ page: "1", limit: "100" });
    if (search) params.set("search", search);
    if (status !== "All") params.set("status", status);
    return params.toString();
  }, [search, status]);

  const loadApplicants = useCallback(async () => {
    setLoading(true);
    setError("");
    try {
      const response = await apiFetch<{ data: Applicant[] }>(`/api/applicants?${query}`);
      setApplicants(response.data);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Unable to load applicants");
    } finally {
      setLoading(false);
    }
  }, [query]);

  useEffect(() => {
    loadApplicants();
  }, [loadApplicants]);

  return (
    <div className="rounded-lg border border-border bg-background shadow-soft">
      <div className="flex flex-col gap-3 border-b border-border p-4 md:flex-row md:items-center md:justify-between">
        <div className="grid gap-3 md:grid-cols-[280px_180px]">
          <Input placeholder="Search name, email, position..." value={search} onChange={(event) => setSearch(event.target.value)} />
          <Select value={status} onChange={(event) => setStatus(event.target.value as ApplicantStatus | "All")}>
            {statuses.map((item) => (
              <option key={item} value={item}>
                {item === "All" ? "All stages" : item}
              </option>
            ))}
          </Select>
        </div>
        <Link href="/applicants/add">
          <Button type="button">Add Applicant</Button>
        </Link>
      </div>
      {error ? <p className="p-4 text-sm text-destructive">{error}</p> : null}
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>Applicant</TableHead>
            <TableHead>Position</TableHead>
            <TableHead>Department</TableHead>
            <TableHead>Stage</TableHead>
            <TableHead>Source</TableHead>
            <TableHead>Owner</TableHead>
            <TableHead className="text-right">Action</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {loading ? (
            <TableRow>
              <TableCell colSpan={7} className="text-center text-muted-foreground">
                Loading applicants...
              </TableCell>
            </TableRow>
          ) : applicants.length === 0 ? (
            <TableRow>
              <TableCell colSpan={7} className="text-center text-muted-foreground">
                No applicants found.
              </TableCell>
            </TableRow>
          ) : (
            applicants.map((applicant) => (
              <TableRow key={applicant.id}>
                <TableCell>
                  <div className="font-medium">{applicant.name}</div>
                  <div className="text-xs text-muted-foreground">{applicant.email}</div>
                </TableCell>
                <TableCell>
                  <div>{applicant.position}</div>
                  <div className="text-xs text-muted-foreground">{applicant.experience}</div>
                </TableCell>
                <TableCell>{applicant.department}</TableCell>
                <TableCell>
                  <ApplicantStatusBadge status={applicant.status} />
                </TableCell>
                <TableCell>{applicant.source}</TableCell>
                <TableCell>{applicant.owner}</TableCell>
                <TableCell className="text-right">
                  <Link className="text-sm font-medium text-primary hover:underline" href={`/applicants/${applicant.id}`}>
                    Open
                  </Link>
                </TableCell>
              </TableRow>
            ))
          )}
        </TableBody>
      </Table>
    </div>
  );
}
